def gen(rng, size):
    import string
    parts = []
    total = 0
    while total < max(1, size):
        wlen = rng.randint(1, 8)
        word = ''.join(rng.choice(string.ascii_letters) for _ in range(wlen))
        parts.append(word)
        total += wlen + 1
    s = ''
    for w in parts:
        s += w + ' ' * rng.randint(1, 3)
    if rng.random() < 0.5:
        s = s.rstrip()
        if not s:
            s = parts[0]
    if not s.strip():
        s = parts[0]
    return [s]

